def solve(grid):
    import numpy as np
    grid = np.array(grid)
    H, W = grid.shape

    # Find the horizontal 6-line
    six_row = None
    for r in range(H):
        if 6 in grid[r]:
            six_row = r
            break

    # For each column, find non-8/non-6 colored cells
    col_info = {}
    for c in range(W):
        non_bg = [r for r in range(H) if grid[r, c] not in [8, 6]]
        if non_bg:
            color = int(grid[non_bg[0], c])
            col_info[c] = (color, len(non_bg), min(non_bg), max(non_bg))

    # Group adjacent columns with same color and height into objects
    objects = []
    visited = set()
    for c in sorted(col_info.keys()):
        if c in visited:
            continue
        color, height, rmin, rmax = col_info[c]
        cols = [c]
        visited.add(c)
        nc = c + 1
        while nc in col_info and col_info[nc][0] == color and col_info[nc][1] == height:
            cols.append(nc)
            visited.add(nc)
            nc += 1
        objects.append((cols, color, height))

    # Sort heights ascending
    heights = [obj[2] for obj in objects]
    sorted_heights = sorted(heights)

    # Build output
    out = np.full((H, W), 8)
    out[six_row] = grid[six_row].copy()

    for idx, (cols, color, old_height) in enumerate(objects):
        new_height = sorted_heights[idx]
        half = (new_height - 1) // 2
        for c in cols:
            for r in range(six_row - half, six_row + half + 1):
                if 0 <= r < H:
                    out[r, c] = color

    return out.tolist()

