    grid = np.array(grid)
    H, W = grid.shape

    six_row = None
    for r in range(H):
        if 6 in grid[r]:
            six_row = r
            break

    col_info = {}
    for c in range(W):
        col = grid[:, c]
        non_bg = [r for r in range(H) if col[r] not in [8, 6]]
        if non_bg:
            color = int(col[non_bg[0]])
            above = six_row - min(non_bg)
            below = max(non_bg) - six_row
            col_info[c] = (color, above, below)

    objects = []
    visited = set()
    for c in sorted(col_info.keys()):
        if c in visited:
            continue
        color, above, below = col_info[c]
        cols = [c]
        visited.add(c)
        nc = c + 1
        while nc in col_info and col_info[nc] == (color, above, below):
            cols.append(nc)
            visited.add(nc)
            nc += 1
        objects.append((cols, color, above, below))

    has_asymmetry = any(above != below for _, _, above, below in objects)

    # Sort by max extent, draw symmetric
    extents = [max(above, below) for _, _, above, below in objects]
    sorted_extents = sorted(extents)
    out1 = np.full((H, W), 8)
    out1[six_row] = grid[six_row].copy()
    for idx, (cols, color, _, _) in enumerate(objects):
        ext = sorted_extents[idx]
        for c in cols:
            for r in range(six_row - ext, six_row + ext + 1):
                if 0 <= r < H:
                    out1[r, c] = color

    if not has_asymmetry:
        return out1.tolist()

    # Candidate 2: sort by total, preserve asymmetry
    shapes = [(above, below) for _, _, above, below in objects]
    sorted_shapes = sorted(shapes, key=lambda x: x[0] + x[1])
